// Parse ElevenLabs post_call webhook payload
const input = $json.body || $json;

// Extract key fields from ElevenLabs payload
const parsed = {
  conversation_id: input.conversation_id || input.data?.conversation_id || 'unknown',
  agent_id: input.agent_id || input.data?.agent_id || '',
  agent_name: input.agent_name || input.data?.agent_name || 'Unknown Agent',
  event_type: input.event_type || input.type || 'post_call',
  caller_phone: input.caller_phone || input.metadata?.caller_phone || '',
  duration_seconds: input.duration_seconds || input.call_duration || 0,
  outcome: input.outcome || input.status || 'unknown',
  transcript_available: !!input.transcript || !!input.data?.transcript,
  errors: input.errors || '',
  timestamp: new Date().toISOString(),
  raw_payload: input
};

return { json: parsed };

// Build payloads for each subworkflow
const data = $json;

// Define subworkflows to call
const subworkflows = [
  {
    name: 'execution_logger',
    url: '{{ $env.WEBHOOK_BASE_URL }}/webhook/log-execution-test',
    payload: {
      conversation_id: data.conversation_id,
      agent_name: data.agent_name,
      caller_phone: data.caller_phone,
      duration_seconds: data.duration_seconds,
      outcome: data.outcome,
      errors: data.errors
    },
    required: true
  },
  {
    name: 'slack_notifier',
    url: '{{ $env.WEBHOOK_BASE_URL }}/webhook/slack-notify-test',
    payload: {
      conversation_id: data.conversation_id,
      agent_name: data.agent_name,
      caller_phone: data.caller_phone,
      duration_seconds: data.duration_seconds,
      outcome: data.outcome,
      summary: 'Post-call processing triggered'
    },
    required: false
  }
];

// In production, would also call transcript extractor if transcript_available
if (data.transcript_available) {
  subworkflows.push({
    name: 'transcript_extractor',
    url: '{{ $env.WEBHOOK_BASE_URL }}/webhook/extract-transcript-v2',
    payload: { conversation_id: data.conversation_id },
    required: false
  });
}

return {
  json: {
    parsed_data: data,
    subworkflows: subworkflows,
    subworkflow_count: subworkflows.length
  }
};

// Aggregate results from all subworkflow calls
const items = $input.all();
const results = {};
let loggerCalled = false;
let slackCalled = false;

// Each item contains the HTTP response from a subworkflow
items.forEach((item) => {
  if (item.json.logged !== undefined) {
    loggerCalled = true;
    results.execution_logger = {
      called: true,
      success: item.json.success !== false,
      response: item.json
    };
  } else if (item.json.slackPayload !== undefined || item.json.slack !== undefined) {
    slackCalled = true;
    results.slack_notifier = {
      called: true,
      success: item.json.success !== false,
      response: item.json
    };
  } else {
    // Fallback - assign based on position
    const key = Object.keys(results).length === 0 ? 'execution_logger' : 'slack_notifier';
    if (key === 'execution_logger') loggerCalled = true;
    if (key === 'slack_notifier') slackCalled = true;
    results[key] = {
      called: true,
      success: item.json.success !== false,
      response: item.json
    };
  }
});

const allSuccess = Object.values(results).every(r => r.success);
const partialSuccess = !allSuccess && Object.values(results).some(r => r.success);

return [{
  json: {
    success: true,
    summary: 'Post-call processing complete',
    logged: loggerCalled,
    notified: slackCalled,
    execution_logger: results.execution_logger || { called: false },
    slack_notifier: results.slack_notifier || { called: false },
    partial_success: partialSuccess,
    orchestration_complete: true,
    all_success: allSuccess,
    subworkflow_results: results,
    timestamp: new Date().toISOString()
  }
}];
